SELECT COUNT(*) as cnt FROM breed
WHERE cat_no=#{cat_no}
WHERE cat_no=#{cat_no} AND (UPPER(breed_name) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(title) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(content) LIKE '%' || UPPER(#{word}) || '%')

SELECT breedno, cat_no, memberno, breed_name, title, content, recom, viewcnt, rdate, origin, kg, height, size_type, r FROM ( SELECT breedno, cat_no, memberno, breed_name, title, content, recom, viewcnt, rdate, origin, kg, height, size_type, rownum as r FROM ( SELECT breedno, cat_no, memberno, breed_name, title, content, recom, viewcnt, rdate, origin, kg, height, size_type FROM breed
WHERE cat_no=#{cat_no}
WHERE cat_no=#{cat_no} AND (UPPER(breed_name) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(title) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(content) LIKE '%' || UPPER(#{word}) || '%')
ORDER BY breedno DESC ) ) WHERE r >= #{start_num} AND r <= #{end_num}

mapper.update:
UPDATE breed
SET breed_name=#{breed_name}, title=#{title}, content=#{content}, 
    origin=#{origin}, kg=#{kg}, height=#{height}, size_type=#{size_type}
WHERE breedno = #{breedno}

UPDATE breed
SET recom = recom + 1
WHERE breedno = #{breedno}

UPDATE breed
SET recom = recom - 1
WHERE breedno = #{breedno}

